static async Task<IResult> HandleUpload(HttpRequest request, IWebHostEnvironment env, string subFolder, long maxBytes)
{
    if (!request.HasFormContentType)
        return Results.BadRequest(new { error = "Expected multipart/form-data." });

    var form = await request.ReadFormAsync();
    var file = form.Files.FirstOrDefault();
    if (file == null || file.Length == 0)
        return Results.BadRequest(new { error = "No file uploaded." });

    if (file.Length > maxBytes)
        return Results.BadRequest(new { error = $"File too large. Max {maxBytes} bytes." });

    var ext = Path.GetExtension(file.FileName)?.ToLowerInvariant() ?? "";
    if (!AllowedExtensions.Contains(ext))
        return Results.BadRequest(new { error = "File type not allowed." });

    var contentType = file.ContentType?.ToLowerInvariant() ?? "";
    if (!IsAllowedContentType(contentType, ext))
        return Results.BadRequest(new { error = "Content type not allowed." });

    var uploadsRoot = Path.Combine(env.ContentRootPath, "wwwroot", "uploads", subFolder);
    Directory.CreateDirectory(uploadsRoot);

    var safeExt = ext.Length > 0 ? ext : ".bin";
    var fileName = $"{DateTimeOffset.UtcNow:yyyyMMddHHmmssfff}_{Guid.NewGuid():N}{safeExt}";
    var physicalPath = Path.Combine(uploadsRoot, fileName);

    await using (var stream = File.Create(physicalPath))
    {
        await file.CopyToAsync(stream);
    }

    var relativePath = $"/uploads/{subFolder}/{fileName}";
    return Results.Ok(new
    {
        path = relativePath,
        fileName = file.FileName,
        storedAs = fileName,
        size = file.Length,
        contentType = file.ContentType
    });
}

